+        return build_numpy_complex_vector_from_flat_interleaved(py, result.values());
+    }
+
+    let numpy = py.import("numpy")?;
+    Ok(numpy
+        .getattr("linalg")?
+        .getattr("eigvals")?
+        .call1((a.bind(py),))?
+        .unbind())
